head.script:
scwin.onpageload = function () {
    window.setTimeout(function () { scwin._loadData(); }, 50);
};

scwin._currentFolderId = 1;

scwin._loadData = function () {
    scwin._loadFolders();
};

scwin._buildFolderRows = function (folders) {
    if (window.DamUtils && DamUtils.buildFolderRows) { return DamUtils.buildFolderRows(folders || []); }
    var childrenMap = {};
    var allIds = {};
    for (var i = 0; i < folders.length; i++) { allIds[folders[i].folderId] = true; }
    for (var i = 0; i < folders.length; i++) {
        var pid = folders[i].parentFolderId || 0;
        if (!childrenMap[pid]) { childrenMap[pid] = []; }
        childrenMap[pid].push(folders[i]);
    }
    var roots = [];
    for (var i = 0; i < folders.length; i++) {
        var f = folders[i];
        if (!f.parentFolderId || !allIds[f.parentFolderId]) { roots.push(f); }
    }
    var result = [];
    var visit = function (node, depth) {
        result.push({ FOLDER_ID: String(node.folderId), FOLDER_NM: node.folderNm || '', DEPTH: String(depth) });
        var children = childrenMap[node.folderId] || [];
        for (var j = 0; j < children.length; j++) { visit(children[j], depth + 1); }
    };
    for (var i = 0; i < roots.length; i++) { visit(roots[i], 1); }
    return result;
};

scwin._loadFolders = function () {
    fetch('/api/dam/folders')
        .then(function (r) { return r.json(); })
        .then(function (data) {
            if (!data || !data.length) { return; }
            var rows = scwin._buildFolderRows(data);
            try {
                dlFolder.setJSON(rows);
                window.setTimeout(function () {
                    try { trvFolder.expandAll(); } catch (e) {}
                }, 100);
            } catch (e) { console.warn('[Asset] dlFolder.setJSON error', e); }
        })
        .catch(function (e) { console.warn('[Asset] folders error', e); });
};

scwin._formatFileSize = function (bytes) {
    if (window.DamUtils && DamUtils.formatFileSize) { return DamUtils.formatFileSize(bytes); }
    var n = Number(bytes);
    if (!bytes || isNaN(n) || n === 0) { return '-'; }
    if (n >= 1073741824) { return (n / 1073741824).toFixed(2) + ' GB'; }
    if (n >= 1048576)    { return (n / 1048576).toFixed(2) + ' MB'; }
    if (n >= 1024)       { return (n / 1024).toFixed(1) + ' KB'; }
    return n + ' B';
};

scwin._loadAssets = function (folderId) {
    fetch('/api/dam/assets?folderId=' + (folderId || 1))
        .then(function (r) { return r.json(); })
        .then(function (data) {
            var rows = [];
            for (var i = 0; i < data.length; i++) {
                var d = data[i];
                var icon = ((d.fileExt || d.fileType || '')).toUpperCase().replace('.', '');
                rows.push({
                    CHK: '',
                    ASSET_ID: String(d.assetId || ''),
                    ICON: icon,
                    FILE_NM: d.fileNm || '',
                    FILE_TYPE: d.fileType || '',
                    FILE_SIZE: scwin._formatFileSize(d.fileSize),
                    STATUS: d.status || '',
                    TAGS: d.tags || '',
                    CREATOR: d.ownerNm || '',
                    RESOLUTION: d.resolution || '-',
                    UPLOAD_DT: d.uploadDt || '',
                    PREVIEW_URL: d.previewUrl || '/cm/dam/images/preview/document.svg'
                });
            }
            try { dlAsset.setJSON(rows); } catch (e) { console.warn('[Asset] setJSON failed', e); }
            scwin._clearDetail();
            if (rows.length > 0) {
                window.setTimeout(function () { scwin._styleIconBadges(); }, 100);
                window.setTimeout(function () { scwin._styleIconBadges(); }, 500);
            }
            window.setTimeout(function () { scwin._attachSortOnMousedown(); }, 150);
        })
        .catch(function (e) { console.warn('[Asset] assets error', e); });
};

scwin.trvFolder_onclick = function (treeObj) {
    var nodeValue = trvFolder.getSelectedValue();
    console.log('[Asset] tree onclick selectedValue=' + nodeValue);
    if (!nodeValue) { return; }
    var fid = parseInt(nodeValue, 10);
    if (isNaN(fid) || fid <= 0) { return; }
    if (fid === scwin._currentFolderId) { return; }
    scwin._currentFolderId = fid;
    scwin._loadAssets(fid);
};

scwin.grdAsset_onclick = function () {
    window.setTimeout(function () {
        try {
            var idx = grdAsset.getFocusedRowIndex();
            if (idx >= 0) { scwin._applyDetail(idx, true); }
        } catch (e) {}
    }, 30);
};

scwin._normalizeRowIndex = function (rowLike) {
    var row = rowLike;
    if (row && typeof row === "object") {
        if (typeof row.rowIndex === "number") { row = row.rowIndex; }
        else if (typeof row.newRowIndex === "number") { row = row.newRowIndex; }
        else if (typeof row.index === "number") { row = row.index; }
    }
    row = parseInt(row, 10);
    return isNaN(row) || row < 0 ? -1 : row;
};

scwin._realRowIndex = function (displayRow) {
    var idx = scwin._normalizeRowIndex(displayRow);
    if (idx < 0) { return -1; }
    try {
        if (grdAsset && typeof grdAsset.getRealRowIndex === "function") {
            var real = scwin._normalizeRowIndex(grdAsset.getRealRowIndex(idx));
            if (real >= 0) { return real; }
        }
    } catch (e) {}
    return idx;
};

scwin._showVersionsForGridRow = function (rowLike, forceReload) {
    var idx = scwin._realRowIndex(rowLike);
    if (idx < 0) {
        try { idx = scwin._realRowIndex(grdAsset.getFocusedRowIndex()); } catch (e) {}
    }
    if (idx >= 0) { scwin._applyDetail(idx, !!forceReload); }
};

scwin.grdAsset_onrowindexchange = function (row, oldRow) {
    var idx = scwin._normalizeRowIndex(row);
    if (idx < 0 && arguments.length >= 3) { idx = scwin._normalizeRowIndex(arguments[2]); }
    scwin._showVersionsForGridRow(idx, false);
};

scwin.grdAsset_oncellindexchange = function (row, col, oldRow, oldCol) {
    var idx = scwin._normalizeRowIndex(row);
    var prev = scwin._normalizeRowIndex(oldRow);
    if (idx < 0 && arguments.length >= 3) {
        prev = scwin._normalizeRowIndex(arguments[1]);
        idx = scwin._normalizeRowIndex(arguments[2]);
    }
    if (idx < 0 || idx === prev) { return; }
    scwin._showVersionsForGridRow(idx, false);
};

scwin.grdAsset_oncellclick = function (row, col, colId) {
    if (colId && String(colId).indexOf("hd") === 0) { return; }
    window.setTimeout(function () { scwin._showVersionsForGridRow(row, true); }, 30);
};

scwin._FILE_ICON_COLORS = {
    "PDF": "#f44336", "DOC": "#1e88e5", "DOCX": "#1e88e5",
    "XLS": "#43a047", "XLSX": "#43a047", "PPT": "#ff7043", "PPTX": "#ff7043",
    "JPG": "#43a047", "JPEG": "#43a047", "PNG": "#1e88e5",
    "GIF": "#8e24aa", "SVG": "#00897b", "PSD": "#5e35b1",
    "MP4": "#fb8c00", "MOV": "#f4511e", "AVI": "#f4511e",
    "MP3": "#3949ab", "WAV": "#3949ab", "AAC": "#3949ab",
    "ZIP": "#546e7a", "RAR": "#546e7a", "7Z": "#546e7a"
};

scwin._makeFileIcon = function (ext) {
    if (window.DamUtils && DamUtils.makeFileIcon) { return DamUtils.makeFileIcon(ext); }
    var color = scwin._FILE_ICON_COLORS[ext] || "#546e7a";
    var lbl = String(ext || "FILE").substring(0, 4);
    var svg = '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 32 40">'
        + '<path d="M2,0 L22,0 L32,10 L32,40 L2,40 Z" fill="#ffffff" stroke="#d1d5db" stroke-width="1.5"/>'
        + '<path d="M22,0 L22,10 L32,10 Z" fill="#e5e7eb"/>'
        + '<rect x="2" y="26" width="30" height="14" fill="' + color + '"/>'
        + '<text x="16" y="37" font-family="Arial,sans-serif" font-size="8" font-weight="bold" fill="#ffffff" text-anchor="middle">' + lbl + '</text>'
        + '</svg>';
    return "data:image/svg+xml;charset=utf-8," + encodeURIComponent(svg);
};

scwin._styleIconBadges = function () {
    try {
        var cells = document.querySelectorAll(".dam-asset-grid-view .dam-cell-icon");
        for (var i = 0; i < cells.length; i++) {
            var cell = cells[i];
            var labelEl = cell.querySelector(".w2grid_label");
            var ext = (labelEl ? (labelEl.textContent || labelEl.innerText || "") : (cell.textContent || "")).trim().toUpperCase().replace(".", "");
            if (!ext) { ext = "FILE"; }
            if (labelEl) { labelEl.style.cssText = "display:none!important;visibility:hidden!important;"; }
            var existingImg = cell.querySelector(".dam-icon-img");
            if (existingImg) {
                if (existingImg.alt === ext) { continue; }
                existingImg.parentNode.removeChild(existingImg);
            }
            var img = document.createElement("img");
            img.className = "dam-icon-img";
            img.src = scwin._makeFileIcon(ext);
            img.alt = ext;
            img.style.cssText = "width:28px;height:34px;object-fit:contain;display:block;margin:0 auto;pointer-events:none;";
            cell.appendChild(img);
        }
    } catch (e) { /* ignore */ }
};

scwin.grdAsset_ondrawendrow = function () {
    scwin._styleIconBadges();
};

scwin.grdAsset_onsort = function () {
    window.setTimeout(function () { scwin._styleIconBadges(); }, 50);
    window.setTimeout(function () { scwin._styleIconBadges(); }, 300);
};

scwin._sortState = {};

/* mousedown capture fires before focus-transfer, so works on first click */
scwin._attachSortOnMousedown = function () {
    if (document._damSortAttached) { return; }
    document._damSortAttached = true;

    /* inject initial sort marker into sortable header cells */
    var sortableIdxMap = { 2: true, 3: true, 4: true, 5: true };
    var tryInitIcons = function () {
        var sels = [
            ".dam-asset-grid-view .w2grid_header .w2grid_cell",
            ".dam-asset-grid-view .w2grid_header td",
            ".dam-asset-grid-view .w2grid_header th",
            ".dam-asset-grid-view thead td",
            ".dam-asset-grid-view thead th"
        ];
        var hcells = null;
        for (var s = 0; s < sels.length; s++) {
            var found = document.querySelectorAll(sels[s]);
            if (found && found.length > 0) { hcells = found; break; }
        }
        if (!hcells || !hcells.length) { return; }
        for (var i = 0; i < hcells.length; i++) {
            if (!sortableIdxMap[i]) { continue; }
            if (!hcells[i].querySelector(".dam-sort-indicator")) {
                var sp = document.createElement("span");
                sp.className = "dam-sort-indicator";
                sp.textContent = " <> ";
                sp.style.cssText = "font-size:0.7rem;color:#94a3b8;pointer-events:none;";
                hcells[i].appendChild(sp);
            }
        }
    };
    tryInitIcons();
    window.setTimeout(tryInitIcons, 300);

    document.addEventListener("mousedown", function (e) {
        var target = e.target;
        if (!target || !target.closest) { return; }
        if (!target.closest(".dam-asset-grid-view")) { return; }
        var headerCell =
            target.closest(".w2grid_header .w2grid_cell") ||
            target.closest(".w2grid_header td") ||
            target.closest(".w2grid_header th") ||
            target.closest("thead td") ||
            target.closest("thead th");
        if (!headerCell) { return; }
        var siblings = headerCell.parentElement ? headerCell.parentElement.children : [];
        var idx = -1;
        for (var i = 0; i < siblings.length; i++) {
            if (siblings[i] === headerCell) { idx = i; break; }
        }
        var sortableMap = { 2: "FILE_NM", 3: "FILE_TYPE", 4: "FILE_SIZE", 5: "STATUS" };
        var colId = sortableMap[idx];
        if (!colId) { return; }
        var cur = scwin._sortState[colId] || "none";
        var next = cur === "asc" ? "desc" : "asc";
        scwin._sortState = {};
        scwin._sortState[colId] = next;
        /* build rows array from DataList row-by-row (getJSON may not return array) */
        try {
            var count = dlAsset.getRowCount ? dlAsset.getRowCount() : 0;
            var rows = [];
            for (var r = 0; r < count; r++) { rows.push(dlAsset.getRowJSON(r)); }
            if (rows.length) {
                rows.sort(function (a, b) {
                    var va = String(a[colId] || "");
                    var vb = String(b[colId] || "");
                    return next === "asc"
                        ? va.localeCompare(vb, undefined, { numeric: true })
                        : vb.localeCompare(va, undefined, { numeric: true });
                });
                dlAsset.setJSON(rows);
                scwin._applyDetail(0);
                window.setTimeout(function () { scwin._styleIconBadges(); }, 50);
            }
        } catch (ex) { console.warn("[Asset] sort error", ex); }
        /* update header indicators */
        var old = document.querySelectorAll(".dam-asset-grid-view .dam-sort-indicator");
        for (var j = 0; j < old.length; j++) { old[j].textContent = " <> "; old[j].style.color = "#94a3b8"; }
        var activeInd = headerCell.querySelector(".dam-sort-indicator");
        if (activeInd) {
            activeInd.textContent = next === "asc" ? " ^" : " v";
            activeInd.style.color = "#334155";
        }
    }, true);
};

scwin._escapeHtml = function (value) {
    return String(value == null ? "" : value).replace(/[&<>"']/g, function (ch) {
        return {
            "&": "&amp;",
            "<": "&lt;",
            ">": "&gt;",
            "\"": "&quot;",
            "'": "&#39;"
        }[ch];
    });
};

scwin._getVersionListEl = function () {
    return document.querySelector(".dam-version-list");
};

scwin._setVersionSummary = function (row, asset, versionCount) {
    row = row || {};
    asset = asset || {};
    var fileName = asset.fileNm || row.FILE_NM || "No file selected";
    var ext = (asset.fileExt || row.ICON || row.FILE_TYPE || "--").toString().replace(".", "").toUpperCase();
    if (!ext) { ext = "--"; }
    var type = asset.fileType || row.FILE_TYPE || "-";
    var size = row.FILE_SIZE || scwin._formatFileSize(asset.fileSize) || "-";
    var status = asset.status || row.STATUS || "-";
    var owner = asset.ownerNm || row.CREATOR || "-";
    var previewUrl = asset.previewUrl || row.PREVIEW_URL || "";

    try { txt_versionExt.setValue(ext.substring(0, 4)); } catch (e) {}
    scwin._setVersionThumbnail(previewUrl);
    try { txt_versionFileNm.setValue(fileName); } catch (e) {}
    try { txt_versionFileMeta.setValue(type + " / " + size + " / Owner: " + owner); } catch (e) {}
    try { txt_versionCount.setValue(String(versionCount == null ? 0 : versionCount)); } catch (e) {}
    try { txt_versionLatest.setValue("-"); } catch (e) {}
    try { txt_versionStatus.setValue(status); } catch (e) {}
};

scwin._setVersionThumbnail = function (previewUrl) {
    var iconEl = document.querySelector(".dam-version-file-icon");
    if (!iconEl) { return; }
    var url = previewUrl || "";
    if (!url) {
        iconEl.classList.remove("has-preview");
        iconEl.style.removeProperty("--dam-version-preview");
        return;
    }
    var safeUrl = String(url).replace(/\\/g, "\\\\").replace(/"/g, '\\"');
    iconEl.classList.add("has-preview");
    iconEl.style.setProperty("--dam-version-preview", 'url("' + safeUrl + '")');
};

scwin._renderVersionState = function (title, detail, stateClass) {
    var el = scwin._getVersionListEl();
    if (!el) { return; }
    el.innerHTML =
        '<div class="dam-version-state ' + (stateClass || "") + '">' +
            '<div class="dam-version-state-icon"></div>' +
            '<div class="dam-version-state-title">' + scwin._escapeHtml(title) + '</div>' +
            '<div class="dam-version-state-detail">' + scwin._escapeHtml(detail || "") + '</div>' +
        '</div>';
};

scwin._renderVersions = function (row, asset, versions) {
    var el = scwin._getVersionListEl();
    if (!el) { return; }
    versions = versions || [];
    scwin._versionDetailContext = {
        row: row || {},
        asset: asset || {},
        versions: versions
    };
    if (!versions.length) {
        scwin._renderVersionState("No versions found", "This asset has no version history yet.", "is-empty");
        return;
    }

    var html = [];
    for (var i = 0; i < versions.length; i++) {
        var v = versions[i] || {};
        var verNo = v.verNo || v.versionNo || v.verId || (versions.length - i);
        var versionLabel = /^v/i.test(String(verNo)) ? String(verNo) : "v" + verNo;
        var isLatest = i === 0;
        var uploadDt = v.uploadDt || "-";
        var changeLog = v.changeLog || (isLatest ? "Latest uploaded version." : "Version snapshot.");
        var detailBtn = '<button type="button" class="dam-version-detail-btn" data-version-index="' + i + '">View Detail</button>';

        html.push(
            '<div class="dam-version-card' + (isLatest ? ' is-latest' : '') + '">' +
                '<div class="dam-version-card-head">' +
                    '<div class="dam-version-badge">' + scwin._escapeHtml(versionLabel) + '</div>' +
                    (isLatest ? '<div class="dam-version-latest">Latest</div>' : '') +
                    '<div class="dam-version-date">' + scwin._escapeHtml(uploadDt) + '</div>' +
                '</div>' +
                '<div class="dam-version-log">' + scwin._escapeHtml(changeLog) + '</div>' +
                '<div class="dam-version-card-foot">' +
                    '<span>Version ID: ' + scwin._escapeHtml(v.verId || "-") + '</span>' +
                    detailBtn +
                '</div>' +
            '</div>'
        );
    }
    el.innerHTML = html.join("");
    scwin._bindVersionDetailButtons();

    try {
        var latestNo = versions[0].verNo || versions[0].verId || "-";
        txt_versionLatest.setValue(latestNo === "-" ? "-" : (/^v/i.test(String(latestNo)) ? String(latestNo) : "v" + latestNo));
    } catch (e) {}
};

scwin._versionDetailContext = { row: {}, asset: {}, versions: [] };

scwin._bindVersionDetailButtons = function () {
    var el = scwin._getVersionListEl();
    if (!el || el._damVersionDetailBound) { return; }
    el._damVersionDetailBound = true;
    el.addEventListener("click", function (event) {
        var target = event.target;
        var btn = target && target.closest ? target.closest(".dam-version-detail-btn") : null;
        if (!btn) { return; }
        event.preventDefault();
        event.stopPropagation();
        scwin._showVersionDetail(parseInt(btn.getAttribute("data-version-index"), 10));
    });
};

scwin._getVersionDetailModal = function () {
    var modal = document.querySelector(".dam-version-modal");
    if (modal) { return modal; }
    modal = document.createElement("div");
    modal.className = "dam-version-modal";
    modal.style.display = "none";
    modal.innerHTML =
        '<div class="dam-version-modal-dialog" role="dialog" aria-modal="true">' +
            '<div class="dam-version-modal-head">' +
                '<div>' +
                    '<div class="dam-version-modal-eyebrow">Version Detail</div>' +
                    '<div class="dam-version-modal-title"></div>' +
                '</div>' +
                '<button type="button" class="dam-version-modal-close" aria-label="Close">x</button>' +
            '</div>' +
            '<div class="dam-version-modal-body"></div>' +
        '</div>';
    document.body.appendChild(modal);
    modal.addEventListener("click", function (event) {
        var target = event.target;
        if (target === modal || (target.closest && target.closest(".dam-version-modal-close"))) {
            scwin._closeVersionDetail();
        }
    });
    return modal;
};

scwin._detailFieldHtml = function (label, value, isUrl) {
    var val = value == null || value === "" ? "-" : String(value);
    var renderedValue = scwin._escapeHtml(val);
    if (isUrl && val !== "-") {
        renderedValue = '<a class="dam-version-detail-link" href="' + scwin._escapeHtml(val) + '" target="_blank" rel="noopener">' + scwin._escapeHtml(val) + '</a>';
    }
    return '<div class="dam-version-detail-field">' +
        '<div class="dam-version-detail-label">' + scwin._escapeHtml(label) + '</div>' +
        '<div class="dam-version-detail-value">' + renderedValue + '</div>' +
    '</div>';
};

scwin._detailSectionHtml = function (title, fields) {
    var html = '<div class="dam-version-detail-section">' +
        '<div class="dam-version-detail-section-title">' + scwin._escapeHtml(title) + '</div>' +
        '<div class="dam-version-detail-grid">';
    for (var i = 0; i < fields.length; i++) {
        html += scwin._detailFieldHtml(fields[i][0], fields[i][1], fields[i][2]);
    }
    html += '</div></div>';
    return html;
};

scwin._showVersionDetail = function (versionIndex) {
    var ctx = scwin._versionDetailContext || {};
    var versions = ctx.versions || [];
    if (isNaN(versionIndex) || versionIndex < 0 || versionIndex >= versions.length) { return; }
    var version = versions[versionIndex] || {};
    var asset = ctx.asset || {};
    var row = ctx.row || {};
    var verNo = version.verNo || version.versionNo || version.verId || "-";
    var versionLabel = verNo === "-" ? "-" : (/^v/i.test(String(verNo)) ? String(verNo) : "v" + verNo);
    var fileName = version.fileNm || asset.fileNm || row.FILE_NM || "-";
    var fileSize = asset.fileSize != null ? scwin._formatFileSize(asset.fileSize) : (row.FILE_SIZE || "-");

    var modal = scwin._getVersionDetailModal();
    var titleEl = modal.querySelector(".dam-version-modal-title");
    var bodyEl = modal.querySelector(".dam-version-modal-body");
    if (titleEl) { titleEl.textContent = fileName + " / " + versionLabel; }
    if (bodyEl) {
        bodyEl.innerHTML =
            scwin._detailSectionHtml("Version Information", [
                ["Version No", versionLabel],
                ["Version ID", version.verId],
                ["Asset ID", version.assetId || asset.assetId || row.ASSET_ID],
                ["File Name", fileName],
                ["Owner", version.ownerNm || asset.ownerNm || row.CREATOR],
                ["Uploaded Date", version.uploadDt],
                ["Change Log", version.changeLog],
                ["File URL", version.fileUrl, true],
                ["Preview URL", version.previewUrl || asset.previewUrl || row.PREVIEW_URL, true]
            ]) +
            scwin._detailSectionHtml("Asset Information", [
                ["Asset Name", asset.fileNm || row.FILE_NM],
                ["Type", asset.fileType || row.FILE_TYPE],
                ["Extension", asset.fileExt || row.ICON],
                ["Size", fileSize],
                ["Status", asset.status || row.STATUS],
                ["Tags", asset.tags || row.TAGS],
                ["Resolution", asset.resolution || row.RESOLUTION],
                ["Asset Uploaded", asset.uploadDt || row.UPLOAD_DT]
            ]);
    }
    modal.classList.add("is-open");
};

scwin._closeVersionDetail = function () {
    var modal = document.querySelector(".dam-version-modal");
    if (modal) { modal.classList.remove("is-open"); }
};

scwin._clearDetail = function () {
    scwin._lastDetailRow = -1;
    scwin._editMode = false;
    scwin._versionLoadToken = 0;
    scwin._lastDetailAssetId = "";
    scwin._setVersionSummary(null, null, 0);
    try { txt_versionFileMeta.setValue("Click an item in File List"); } catch (e) {}
    try { txt_versionLatest.setValue("-"); } catch (e) {}
    scwin._renderVersionState("Select a file", "Click an item in File List to view its version history.", "is-empty");
};

scwin._lastDetailRow = -1;
scwin._versionLoadToken = 0;
scwin._lastDetailAssetId = "";

scwin._applyDetail = function (rowIndex, forceReload) {
    if (scwin._editMode) { scwin._editMode = false; }
    scwin._lastDetailRow = rowIndex;

    var row = dlAsset.getRowJSON(rowIndex);
    if (!row || !row.ASSET_ID) {
        scwin._clearDetail();
        return;
    }

    var assetId = String(row.ASSET_ID);
    if (!forceReload && assetId === scwin._lastDetailAssetId) { return; }
    scwin._lastDetailAssetId = assetId;

    scwin._setVersionSummary(row, null, 0);
    scwin._renderVersionState("Loading versions", "Fetching version history for " + (row.FILE_NM || "selected file") + ".", "is-loading");

    var token = ++scwin._versionLoadToken;
    fetch('/api/dam/assets/' + encodeURIComponent(assetId))
        .then(function (r) {
            if (!r.ok) { throw new Error("HTTP " + r.status); }
            return r.json();
        })
        .then(function (data) {
            if (token !== scwin._versionLoadToken) { return; }
            var asset = data && data.asset ? data.asset : {};
            var versions = data && data.versions ? data.versions : [];
            scwin._setVersionSummary(row, asset, versions.length);
            scwin._renderVersions(row, asset, versions);
        })
        .catch(function (e) {
            if (token !== scwin._versionLoadToken) { return; }
            console.warn("[Version] load failed", e);
            scwin._renderVersionState("Unable to load versions", "Please select the file again or refresh this page.", "is-error");
        });
};
